((java.util.function.IntSupplier) () -> {
    if (agent.slotIndex >= 0) return agent.slotIndex + 1;
    int target = -1;
    for (int i = 0; i < 4; i++) {
        if (slotBranches[i] == agent.branchId) { target = i; break; }
    }
    if (target == -1) {
        for (int i = 0; i < 4; i++) {
            if (slotBranches[i] == 0) {
                slotBranches[i] = agent.branchId;
                target = i;
                break;
            }
        }
    }
    if (target == -1) {
        int minRem = Integer.MAX_VALUE;
        for (int i = 0; i < 4; i++) {
            int rem = branchRemainingTotal.getOrDefault(slotBranches[i], 0);
            if (rem < minRem) { minRem = rem; target = i; }
        }
    }
    agent.slotIndex = target;
    return target + 1;
}).getAsInt()
